document.addEventListener("page:loaded",()=>{CONFIG.page.comments&&NexT.utils.loadComments("#disqus_thread").then(()=>NexT.utils.getScript(CONFIG.disqusjs.js,{condition:window.DisqusJS})).then(()=>{window.dsqjs=new DisqusJS({api:CONFIG.disqusjs.api||"https://disqus.com/api/",apikey:CONFIG.disqusjs.apikey,shortname:CONFIG.disqusjs.shortname,url:CONFIG.page.permalink,identifier:CONFIG.page.path,title:CONFIG.page.title})})});